module skip_fifo #(
    parameter integer WIDTH = 8,
    parameter integer DEPTH = 16
) (
    input  wire              clk,
    input  wire              rst_n,
    input  wire              in_valid,
    input  wire [WIDTH-1:0]  in_data,
    output wire              in_ready,
    output wire              out_valid,
    output wire [WIDTH-1:0]  out_data,
    input  wire              out_ready
);
    // DEPTH must be a power of 2; ADDR_W = log2(DEPTH).
    function integer clog2;
        input integer value;
        integer v;
        begin
            v = value - 1;
            for (clog2 = 0; v > 0; clog2 = clog2 + 1) v = v >> 1;
        end
    endfunction
    localparam integer ADDR_W = clog2(DEPTH);

    reg [WIDTH-1:0] mem [0:DEPTH-1];
    reg [ADDR_W:0]  wr_ptr;
    reg [ADDR_W:0]  rd_ptr;

    wire [ADDR_W-1:0] wr_idx = wr_ptr[ADDR_W-1:0];
    wire [ADDR_W-1:0] rd_idx = rd_ptr[ADDR_W-1:0];
    wire empty = (wr_ptr == rd_ptr);
    // full when low bits match but top bit differs (one-extra-bit pointer trick).
    wire full  = (wr_ptr[ADDR_W] != rd_ptr[ADDR_W]) &&
                 (wr_ptr[ADDR_W-1:0] == rd_ptr[ADDR_W-1:0]);

    assign in_ready  = ~full;
    assign out_valid = ~empty;
    assign out_data  = mem[rd_idx];

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            wr_ptr <= {(ADDR_W+1){1'b0}};
            rd_ptr <= {(ADDR_W+1){1'b0}};
        end else begin
            if (in_valid && ~full)        wr_ptr <= wr_ptr + 1'b1;
            if (out_ready && ~empty)      rd_ptr <= rd_ptr + 1'b1;
        end
    end

    // Array-memory write split out per knowledge/patterns/protected/08_common_bugs.md.
    always @(posedge clk) begin
        if (in_valid && ~full) mem[wr_idx] <= in_data;
    end
endmodule

module uram_weight_bank #(
    parameter integer DEPTH         = 1024,
    parameter integer ADDR_W        = 17,
    parameter         MEM_INIT_FILE = ""
) (
    input  wire                    clk,
    input  wire [ADDR_W-1:0]       rd_addr,
    output wire [287:0]            rd_data,
    input  wire                    rd_en
);
`ifdef NN2RTL_SYNTHESIS
    // Vivado-only: forces URAM via XPM. MEM_INIT_FILE is a .mem file.
    xpm_memory_sprom #(
        .ADDR_WIDTH_A(ADDR_W),
        .AUTO_SLEEP_TIME(0),
        .CASCADE_HEIGHT(0),
        .ECC_MODE("no_ecc"),
        .MEMORY_INIT_FILE(MEM_INIT_FILE),
        .MEMORY_INIT_PARAM(""),
        .MEMORY_OPTIMIZATION("true"),
        .MEMORY_PRIMITIVE("ultra"),
        .MEMORY_SIZE(DEPTH * 288),
        .MESSAGE_CONTROL(0),
        .READ_DATA_WIDTH_A(288),
        .READ_LATENCY_A(2),
        .READ_RESET_VALUE_A("0"),
        .RST_MODE_A("SYNC"),
        .SIM_ASSERT_CHK(0),
        .USE_MEM_INIT(1),
        .USE_MEM_INIT_MMI(0),
        .WAKEUP_TIME("disable_sleep")
    ) u_xpm (
        .douta(rd_data),
        .addra(rd_addr),
        .clka(clk),
        .ena(rd_en),
        .rsta(1'b0),
        .regcea(1'b1),
        .sleep(1'b0),
        .injectdbiterra(1'b0),
        .injectsbiterra(1'b0),
        .dbiterra(),
        .sbiterra()
    );
`else
    // Behavioral path for Verilator/iverilog. MEM_INIT_FILE is a .hex file.
    // 2-cycle read latency to match XPM URAM READ_LATENCY_A=2.
    reg [287:0] mem [0:DEPTH-1];
    initial begin
        if (MEM_INIT_FILE != "") $readmemh(MEM_INIT_FILE, mem);
    end
    reg [287:0] rd_data_r1, rd_data_r2;
    always @(posedge clk) begin
        if (rd_en) rd_data_r1 <= mem[rd_addr];
        rd_data_r2 <= rd_data_r1;
    end
    assign rd_data = rd_data_r2;
`endif
endmodule

module stream_to_act_bram_bridge #(
    parameter integer BUS_W            = 2048,
    parameter integer BRAM_BASE_ADDR   = 0,
    parameter integer TOTAL_BRAM_WORDS = 1,
    // [PARTIAL-WORD FLUSH 2026-06-02] Exact producer beat count. 0 = disabled
    // (legacy behaviour: only full BEATS_PER_WORD-beat words are written, so a
    // producer whose beat count is NOT a multiple of BEATS_PER_WORD loses its
    // final partial word -> loader under-fills -> S_WAIT_LOAD/S_WAIT_DRAIN wedge
    // or silently-dropped tail positions). When >0, the g_w_lt branch also flushes
    // the final partial word on beat (TOTAL_BEATS-1) so all positions are stored.
    parameter integer TOTAL_BEATS      = 0
) (
    input  wire             clk,
    input  wire             rst_n,
    input  wire             in_valid,
    input  wire [BUS_W-1:0] in_data,
    output reg              wr_req,
    input  wire             wr_grant,
    output reg  [14:0]      wr_addr,
    output reg  [2047:0]    wr_data,
    output reg              loaded,
    // in_ready: the bridge can capture an input beat THIS cycle. Combinational,
    // for upstream backpressure (stem-segment elastic chain). Existing
    // instances that leave it unconnected are unaffected (push-only as before).
    output wire             in_ready
);
    // in_ready is driven per-generate-branch below (each branch's capture
    // condition is in_valid && !loaded && (!skid_valid || drain_skid); the
    // capacity part -- !loaded && (!skid_valid || drain_skid) -- is in_ready).
    // Word counter (BRAM words written so far).
    reg [15:0] word_count;
    wire [15:0] next_word_count = word_count + 16'd1;
    // bridge_free pulses when wr_req is empty OR being granted this cycle.
    wire bridge_free = !wr_req || (wr_req && wr_grant);
    // wr_addr to use when bridge_free fires this cycle (use next_word_count
    // if a grant just retired the previous wr_req).
    wire [14:0] next_wr_addr = BRAM_BASE_ADDR[14:0]
                             + ((wr_req && wr_grant) ? next_word_count[14:0]
                                                     : word_count[14:0]);

    generate
    if (BUS_W == 2048) begin : g_w_eq
        // 13a audit fix (Fix 12): 1-deep producer-side skid buffer.
        // Previously the old "else if (in_valid && !wr_req)" guard dropped
        // every beat that arrived while wr_req was pending — including the
        // every-other-cycle case where grant+beat coincide. The skid lets
        // us accept a beat in cycle N while wr_data from cycle N-1 is
        // still on the bus, then submit it cycle N+1. Steady-state grant
        // yields one BRAM write per beat, lossless.
        //
        // Known limitation: multi-cycle grant denial (when several bridges
        // and the engine all contend) still drops beats after the skid
        // fills. For the ResNet-50 schedule's mild contention pattern this
        // is rare; a deeper FIFO can be added later if it becomes a hot
        // path in Verilator simulation.
        reg [2047:0] skid_data;
        reg          skid_valid;
        wire         drain_skid = skid_valid && bridge_free;
        assign in_ready = !loaded && (!skid_valid || drain_skid);
        always @(posedge clk or negedge rst_n) begin
            if (!rst_n) begin
                wr_req     <= 1'b0;
                wr_addr    <= 15'd0;
                wr_data    <= 2048'd0;
                word_count <= 16'd0;
                loaded     <= 1'b0;
                skid_valid <= 1'b0;
                skid_data  <= 2048'd0;
            end else begin
                // (1) Grant retires wr_req and advances count.
                if (wr_req && wr_grant) begin
                    wr_req <= 1'b0;
                    word_count <= next_word_count;
                    if (next_word_count == TOTAL_BRAM_WORDS) loaded <= 1'b1;
                end
                // (2) Drain skid into wr_req when bridge is free.
                if (drain_skid) begin
                    wr_req  <= 1'b1;
                    wr_addr <= next_wr_addr;
                    wr_data <= skid_data;
                end
                // (3) Capture new beat into skid; clear skid if drained and no new.
                if (in_valid && !loaded && (!skid_valid || drain_skid)) begin
                    skid_valid <= 1'b1;
                    skid_data  <= in_data;
                end else if (drain_skid) begin
                    skid_valid <= 1'b0;
                end
            end
        end
    end else if (BUS_W < 2048) begin : g_w_lt
        // [1-PX/WORD FIX 2026-06-03] Each narrow beat IS one complete pixel
        // (channels in low BUS_W bits, INT8 byte per channel, channel c at byte c
        // since BUS_W==IC*8). Emit ONE zero-extended 2048-bit BRAM word per beat
        // at addr=base+beat_index, so the engine's 1-px/word read (address_generator:
        // ic_chunks_total=1 -> addr=base+in_r*IW+in_c, channel c at byte c) sees the
        // right pixel. Mirrors the g_w_eq branch exactly EXCEPT zero-extending the
        // BUS_W bits to 2048. The OLD branch accumulated BEATS_PER_WORD=2048/BUS_W
        // pixels per word (channel-chunk semantics) which the engine cannot read for
        // a pointwise low-OC input -> subsampled/scrambled activations (the e2e
        // byte-mismatch root cause). TOTAL_BRAM_WORDS for these instances MUST equal
        // the BEAT count (= H*W) or `loaded` never asserts (S_WAIT_LOAD deadlock).
        // (Equivalent to the old branch for the BPW=1 loaders: they already emitted
        // one zero-extended word per beat.) TOTAL_BEATS is now unused here.
        reg [BUS_W-1:0] skid_data;
        reg             skid_valid;
        wire            drain_skid = skid_valid && bridge_free;
        assign in_ready = !loaded && (!skid_valid || drain_skid);
        always @(posedge clk or negedge rst_n) begin
            if (!rst_n) begin
                wr_req     <= 1'b0;
                wr_addr    <= 15'd0;
                wr_data    <= 2048'd0;
                word_count <= 16'd0;
                loaded     <= 1'b0;
                skid_valid <= 1'b0;
                skid_data  <= {BUS_W{1'b0}};
            end else begin
                // (1) Grant retires wr_req and advances count.
                if (wr_req && wr_grant) begin
                    wr_req <= 1'b0;
                    word_count <= next_word_count;
                    if (next_word_count == TOTAL_BRAM_WORDS) loaded <= 1'b1;
                end
                // (2) Drain skid -> ONE zero-extended word per beat (1 beat = 1 pixel).
                if (drain_skid) begin
                    wr_req  <= 1'b1;
                    wr_addr <= next_wr_addr;
                    wr_data <= { {(2048-BUS_W){1'b0}}, skid_data };
                end
                // (3) Capture new beat into skid.
                if (in_valid && !loaded && (!skid_valid || drain_skid)) begin
                    skid_valid <= 1'b1;
                    skid_data  <= in_data;
                end else if (drain_skid) begin
                    skid_valid <= 1'b0;
                end
            end
        end
    end else begin : g_w_gt
        // BUS_W > 2048: each beat carries WORDS_PER_BEAT BRAM words.
        // 1-deep skid lets a new beat be queued while the current
        // is still being sliced.
        localparam integer WORDS_PER_BEAT = BUS_W / 2048;
        localparam integer SLICE_W = $clog2(WORDS_PER_BEAT);
        reg [BUS_W-1:0] beat_buf;
        reg [SLICE_W:0] slice_idx;
        reg             buf_active;
        reg [BUS_W-1:0] skid_data;
        reg             skid_valid;
        // [LUT-CUT 2026-06-07] Cut 2: the "continue slicing" path below reads
        //   beat_buf[(slice_idx+1)*2048 +: 2048]
        // with a VARIABLE base -> a wide barrel-mux in synthesis. The continue
        // branch only runs for slice_idx in {0 .. WORDS_PER_BEAT-2}, so it only
        // ever reads word indices {1 .. WORDS_PER_BEAT-1} -- all in range. Re-express
        // as a FIXED mux of CONSTANT 2048-bit slices selected by slice_idx; byte-exact
        // by construction (same word for every reachable slice_idx) and no variable
        // part-select. The unreachable arm (slice_idx == WORDS_PER_BEAT-1) defaults to
        // word 1 (never used; also kept in range so no out-of-range part-select).
        reg [2047:0] cont_slice;
        integer cs_i;
        always @(*) begin
            cont_slice = beat_buf[1*2048 +: 2048];   // default = word 1 (safe, in range)
            for (cs_i = 0; cs_i < WORDS_PER_BEAT-1; cs_i = cs_i + 1)
                if (slice_idx == cs_i)
                    cont_slice = beat_buf[(cs_i+1)*2048 +: 2048];  // CONSTANT offset
        end
        wire beat_complete = buf_active && wr_req && wr_grant
                           && (slice_idx == WORDS_PER_BEAT - 1);
        wire can_load_new  = !buf_active || beat_complete;
        wire drain_skid    = skid_valid && can_load_new;
        assign in_ready = !loaded && (!skid_valid || drain_skid);
        always @(posedge clk or negedge rst_n) begin
            if (!rst_n) begin
                wr_req     <= 1'b0;
                wr_addr    <= 15'd0;
                wr_data    <= 2048'd0;
                word_count <= 16'd0;
                beat_buf   <= {BUS_W{1'b0}};
                slice_idx  <= {(SLICE_W+1){1'b0}};
                buf_active <= 1'b0;
                loaded     <= 1'b0;
                skid_valid <= 1'b0;
                skid_data  <= {BUS_W{1'b0}};
            end else begin
                // (1) Grant retires wr_req and advances count.
                if (wr_req && wr_grant) begin
                    wr_req <= 1'b0;
                    word_count <= next_word_count;
                    if (next_word_count == TOTAL_BRAM_WORDS) loaded <= 1'b1;
                    if (slice_idx == WORDS_PER_BEAT - 1) begin
                        slice_idx  <= {(SLICE_W+1){1'b0}};
                        buf_active <= 1'b0;
                    end else if (next_word_count != TOTAL_BRAM_WORDS) begin
                        // Continue slicing the current beat (defensive guard
                        // on next_word_count so we don't overrun TOTAL_BRAM_WORDS
                        // when a frame ends mid-beat with a non-divisible total).
                        slice_idx <= slice_idx + 1'b1;
                        wr_req    <= 1'b1;
                        wr_addr   <= BRAM_BASE_ADDR[14:0] + next_word_count[14:0];
                        // [LUT-CUT 2026-06-07] Cut 2: fixed-mux constant slice (byte-exact
                        // to beat_buf[(slice_idx+1)*2048 +: 2048] for all reachable slice_idx)
                        wr_data   <= cont_slice;
                    end
                end
                // (2) Load new beat from skid when buf is free.
                if (drain_skid) begin
                    beat_buf   <= skid_data;
                    buf_active <= 1'b1;
                    slice_idx  <= {(SLICE_W+1){1'b0}};
                    wr_req     <= 1'b1;
                    wr_addr    <= next_wr_addr;
                    wr_data    <= skid_data[2047:0];
                end
                // (3) Capture new beat into skid.
                if (in_valid && !loaded && (!skid_valid || drain_skid)) begin
                    skid_valid <= 1'b1;
                    skid_data  <= in_data;
                end else if (drain_skid) begin
                    skid_valid <= 1'b0;
                end
            end
        end
    end
    endgenerate
endmodule

module act_unified_mem #(
    parameter integer DEPTH  = 24576,
    parameter integer ADDR_W = 15
) (
    input  wire                    clk,
    input  wire [ADDR_W-1:0]       rd_addr,
    input  wire                    rd_en,
    output reg  [2047:0]           rd_data,
    input  wire [ADDR_W-1:0]       wr_addr,
    input  wire                    wr_en,
    input  wire [2047:0]           wr_data
);
    (* ram_style = "ultra" *) reg [2047:0] mem [0:DEPTH-1];
    always @(posedge clk) begin
        if (rd_en) rd_data <= mem[rd_addr];
    end
    // Array-memory write split into its own always block per
    // knowledge/patterns/protected/08_common_bugs.md §"Array memory
    // write in async-reset block" — no reset clause here.
    always @(posedge clk) begin
        if (wr_en) mem[wr_addr] <= wr_data;
    end
endmodule

module engine_output_fifo #(
    parameter integer DEPTH  = 4096,
    parameter integer ADDR_W = 12,             // log2(DEPTH)
    parameter integer DATA_W = 2048
) (
    input  wire             clk,
    input  wire             rst_n,
    input  wire             in_valid,
    input  wire [DATA_W-1:0] in_data,
    output wire             in_ready,
    output reg              out_valid,
    output reg  [DATA_W-1:0] out_data,
    input  wire             out_ready
);
    (* ram_style = "ultra" *) reg [DATA_W-1:0] mem [0:DEPTH-1];
    reg [ADDR_W:0] wr_ptr;
    reg [ADDR_W:0] rd_ptr;

    wire fifo_empty = (wr_ptr == rd_ptr);
    wire fifo_full  = (wr_ptr[ADDR_W-1:0] == rd_ptr[ADDR_W-1:0])
                    && (wr_ptr[ADDR_W] != rd_ptr[ADDR_W]);
    wire wr_fire = in_valid && !fifo_full;
    wire load_skid = !fifo_empty && (!out_valid || (out_valid && out_ready));
    assign in_ready = !fifo_full;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            wr_ptr    <= {(ADDR_W+1){1'b0}};
            rd_ptr    <= {(ADDR_W+1){1'b0}};
            out_valid <= 1'b0;
            out_data  <= {DATA_W{1'b0}};
        end else begin
            if (wr_fire) wr_ptr <= wr_ptr + 1'b1;
            // Output handshake: drop valid when consumer accepts.
            if (out_valid && out_ready) begin
                out_valid <= 1'b0;
            end
            // Refill output skid when it is empty (or being consumed
            // this cycle) and the FIFO has data. rd_ptr advances on the
            // same edge so the next refill reads the next entry.
            if (load_skid) begin
                out_data  <= mem[rd_ptr[ADDR_W-1:0]];
                out_valid <= 1'b1;
                rd_ptr    <= rd_ptr + 1'b1;
            end
        end
    end
    // Memory write split into its own clock-only always block per
    // knowledge/patterns/protected/08_common_bugs.md.
    always @(posedge clk) begin
        if (wr_fire) mem[wr_ptr[ADDR_W-1:0]] <= in_data;
    end
endmodule

module bias_mem #(
    parameter integer SIZE_WORDS    = 256,
    parameter integer WORD_WIDTH    = 8192,
    parameter integer ADDR_W        = 16,
    parameter         MEM_INIT_FILE = "output/weights/bias.mem"
) (
    input  wire                    clk,
    input  wire [ADDR_W-1:0]       rd_addr,
    output reg  [WORD_WIDTH-1:0]   rd_data,
    input  wire                    rd_en
);
    (* ram_style = "block" *) reg [WORD_WIDTH-1:0] mem [0:SIZE_WORDS-1];
    initial begin
        if (MEM_INIT_FILE != "") $readmemh(MEM_INIT_FILE, mem);
    end
    always @(posedge clk) begin
        if (rd_en) rd_data <= mem[rd_addr];
    end
endmodule

module engine_output_bridge #(
    parameter integer SLOT           = 0,
    parameter integer ACT_W          = 2048,
    parameter integer DATA_W         = 2048,
    parameter integer EXPECTED_BEATS = 1,
    parameter integer NUM_DISPATCHES = 14,
    // [HIGH-OC CONTRACT FIX 2026-06-02] OC>256 dispatches: the engine writes
    // ceil(OC/256) FULL 2048b beats PER POSITION (position-outer/oc-pass-inner,
    // last beat carrying OC-256*(passes-1) channels in its LOW bits — verified vs
    // address_generator.v). OUT_KIND selects how to deliver them downstream:
    //   0 = legacy LOW-OC (1 padded/sliced tile per beat) — BYTE-IDENTICAL to the
    //       prior TILES_PER_BEAT=1 fix; used by every OC<=256 slot. UNCHANGED.
    //   1 = tiled-256: emit 256b tiles, 8 per full beat + ceil(LAST_OC/32) for the
    //       partial last beat of each position => ceil(OC/32) real tiles/pos.
    //   2 = flat-gather: gather BEATS_PER_POS engine beats into one contiguous
    //       OC*8-bit beat per position (for a full-width flat consumer, OC<=512).
    parameter integer OC             = 0,
    parameter integer OUT_KIND       = 0,
    parameter integer POSITIONS      = 1   // OH*OW (high-OC EXPECTED_TILES base)
) (
    input  wire              clk,
    input  wire              rst_n,
    input  wire              start,                 // sched_engine_output_ready
    input  wire              fifo_out_valid,
    input  wire [ACT_W-1:0]  fifo_out_data,
    output wire              fifo_out_ready,
    input  wire              ready_out,             // downstream consumer's ready_in
    output reg               valid_out,
    output reg  [DATA_W-1:0] data_out,
    output reg               drain_complete         // 1 = this dispatch's beats fully drained
);
    // dispatch_count gates active_slot; ticks once per scheduler 'start' pulse.
    localparam integer DC_W = ((NUM_DISPATCHES <= 1) ? 1 : $clog2(NUM_DISPATCHES)) + 1;
    reg [DC_W-1:0] dispatch_count;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) dispatch_count <= {DC_W{1'b0}};
        else if (start) dispatch_count <= dispatch_count + {{(DC_W-1){1'b0}}, 1'b1};
    end
    wire active_slot = (dispatch_count == SLOT[DC_W-1:0]);

    generate
    if (OUT_KIND == 0) begin : g_legacy
        // ===== LOW-OC legacy (byte-identical to the prior TILES_PER_BEAT=1 fix) =====
        localparam integer TILES_PER_BEAT = 1;
        localparam integer TILE_IDX_W    = (TILES_PER_BEAT <= 1) ? 1 : $clog2(TILES_PER_BEAT);
        localparam integer EXPECTED_TILES = EXPECTED_BEATS * TILES_PER_BEAT;
        reg [ACT_W-1:0]      beat_buf;
        reg                  buf_valid;
        reg [TILE_IDX_W:0]   tile_idx;
        reg [31:0]           tiles_emitted;
        wire [DATA_W-1:0] current_tile;
        if (DATA_W >= ACT_W) begin : g_pad
            assign current_tile = { {(DATA_W-ACT_W){1'b0}}, beat_buf };
        end else begin : g_slice
            assign current_tile = beat_buf[tile_idx * DATA_W +: DATA_W];
        end
        wire emit_ready = active_slot && (!valid_out || ready_out)
                        && !drain_complete && buf_valid;
        wire last_tile  = (tile_idx == (TILES_PER_BEAT[TILE_IDX_W:0] - 1'b1));
        wire need_new_beat = !buf_valid || (emit_ready && last_tile);
        assign fifo_out_ready = active_slot && fifo_out_valid
                              && need_new_beat && !drain_complete;
        always @(posedge clk or negedge rst_n) begin
            if (!rst_n) begin
                valid_out      <= 1'b0;
                data_out       <= {DATA_W{1'b0}};
                beat_buf       <= {ACT_W{1'b0}};
                buf_valid      <= 1'b0;
                tile_idx       <= {(TILE_IDX_W+1){1'b0}};
                tiles_emitted  <= 32'd0;
                drain_complete <= 1'b0;
            end else begin
                if (valid_out && ready_out) valid_out <= 1'b0;
                if (emit_ready) begin
                    valid_out     <= 1'b1;
                    data_out      <= current_tile;
                    tiles_emitted <= tiles_emitted + 32'd1;
                    if (tiles_emitted + 32'd1 == EXPECTED_TILES[31:0]) drain_complete <= 1'b1;
                    if (last_tile) begin
                        buf_valid <= 1'b0;
                        tile_idx  <= {(TILE_IDX_W+1){1'b0}};
                    end else begin
                        tile_idx  <= tile_idx + 1'b1;
                    end
                end
                if (fifo_out_ready && fifo_out_valid) begin
                    beat_buf  <= fifo_out_data;
                    buf_valid <= 1'b1;
                    tile_idx  <= {(TILE_IDX_W+1){1'b0}};
                end
            end
        end
    end else if (OUT_KIND == 1) begin : g_tiled
        // ===== HIGH-OC tiled-256: variable real-tiles per beat =====
        localparam integer BEATS_PER_POS = (OC*8 + ACT_W - 1) / ACT_W;     // ceil(OC/256)
        localparam integer LAST_OC       = OC - 256*(BEATS_PER_POS-1);     // ch in last beat
        localparam integer TILES_FULL    = ACT_W / 256;                    // 8
        localparam integer TILES_LAST    = (LAST_OC + 31) / 32;            // ceil(LAST_OC/32)
        localparam integer TILES_PER_POS = (BEATS_PER_POS-1)*TILES_FULL + TILES_LAST;
        localparam integer EXPECTED_TILES = POSITIONS * TILES_PER_POS;
        reg [ACT_W-1:0] beat_buf;
        reg             buf_valid;
        reg [6:0]       tile_idx;        // 0..TILES_FULL-1 (<=8)
        reg [15:0]      beat_in_pos;     // 0..BEATS_PER_POS-1 (index of beat in beat_buf)
        // [GATHER-ASSEMBLY FIX 2026-06-03] pull_idx = index of the NEXT engine beat
        // to be LOADED into beat_buf. It is driven purely by pull events and wraps at
        // BEATS_PER_POS, so it is independent of buf_valid timing. The prior code set
        // beat_in_pos <= is_last_beat ? 0 : beat_in_pos+1 on every pull, which on the
        // FIRST pull of the frame (beat_in_pos=0, is_last_beat=0) wrongly advanced to
        // 1 -> the whole frame ran one beat ahead, so the 2nd beat of each position was
        // mis-classified as the LAST beat (real_tiles=TILES_LAST instead of TILES_FULL).
        // That dropped TILES_FULL-TILES_LAST tiles per position (e.g. 6 tiles for
        // OC=576: ch320..511) and de-synced the engine FIFO for ALL later positions
        // (first-wrong at pixel0 ch320 / tile10). A naive "(is_last_beat||!buf_valid)"
        // guard fixes the no-stall case but BREAKS under mid-position FIFO starvation
        // (a delayed continuation pull sees !buf_valid and resets to 0). The pull-driven
        // counter below is stall-safe. Verified byte-exact on the 576 AND 960 g_tiled
        // chains, with and without injected FIFO stalls (scratch/g876_chain*).
        reg [15:0]      pull_idx;
        reg [31:0]      tiles_emitted;
        wire is_last_beat = (beat_in_pos == (BEATS_PER_POS-1));
        wire [6:0] real_tiles = is_last_beat ? TILES_LAST[6:0] : TILES_FULL[6:0];
        wire [DATA_W-1:0] current_tile = beat_buf[tile_idx*256 +: 256];
        wire emit_ready = active_slot && (!valid_out || ready_out)
                        && !drain_complete && buf_valid;
        wire last_tile  = (tile_idx == (real_tiles - 7'd1));
        wire need_new_beat = !buf_valid || (emit_ready && last_tile);
        assign fifo_out_ready = active_slot && fifo_out_valid
                              && need_new_beat && !drain_complete;
        always @(posedge clk or negedge rst_n) begin
            if (!rst_n) begin
                valid_out<=1'b0; data_out<={DATA_W{1'b0}}; beat_buf<={ACT_W{1'b0}};
                buf_valid<=1'b0; tile_idx<=7'd0; beat_in_pos<=16'd0; pull_idx<=16'd0;
                tiles_emitted<=32'd0; drain_complete<=1'b0;
            end else begin
                if (valid_out && ready_out) valid_out <= 1'b0;
                if (emit_ready) begin
                    valid_out     <= 1'b1;
                    data_out      <= current_tile;
                    tiles_emitted <= tiles_emitted + 32'd1;
                    if (tiles_emitted + 32'd1 == EXPECTED_TILES[31:0]) drain_complete <= 1'b1;
                    if (last_tile) begin buf_valid <= 1'b0; tile_idx <= 7'd0; end
                    else                 tile_idx <= tile_idx + 7'd1;
                end
                // pull next engine beat + set its position-relative index from the
                // pull-driven pull_idx (stall-safe; see GATHER-ASSEMBLY FIX above).
                if (fifo_out_ready && fifo_out_valid) begin
                    beat_buf    <= fifo_out_data;
                    buf_valid   <= 1'b1;
                    tile_idx    <= 7'd0;
                    beat_in_pos <= pull_idx;
                    pull_idx    <= (pull_idx == (BEATS_PER_POS-1)) ? 16'd0
                                                                   : (pull_idx + 16'd1);
                end
            end
        end
    end else begin : g_flat
        // ===== HIGH-OC flat-gather: BEATS_PER_POS beats -> 1 contiguous OC*8b beat =====
        localparam integer BEATS_PER_POS = (OC*8 + ACT_W - 1) / ACT_W;
        localparam integer GW = BEATS_PER_POS * ACT_W;
        localparam integer EXPECTED_TILES = POSITIONS;
        reg [GW-1:0]  gather_buf;
        reg [15:0]    beat_in_pos;
        reg           buf_full;
        reg [31:0]    tiles_emitted;
        wire [DATA_W-1:0] current_tile = gather_buf[DATA_W-1:0];   // low OC*8 bits = contiguous channels
        wire emit_ready = active_slot && (!valid_out || ready_out)
                        && !drain_complete && buf_full;
        assign fifo_out_ready = active_slot && fifo_out_valid
                              && !buf_full && !drain_complete;
        always @(posedge clk or negedge rst_n) begin
            if (!rst_n) begin
                valid_out<=1'b0; data_out<={DATA_W{1'b0}}; gather_buf<={GW{1'b0}};
                beat_in_pos<=16'd0; buf_full<=1'b0; tiles_emitted<=32'd0; drain_complete<=1'b0;
            end else begin
                if (valid_out && ready_out) valid_out <= 1'b0;
                if (emit_ready) begin
                    valid_out     <= 1'b1;
                    data_out      <= current_tile;
                    tiles_emitted <= tiles_emitted + 32'd1;
                    if (tiles_emitted + 32'd1 == EXPECTED_TILES[31:0]) drain_complete <= 1'b1;
                    buf_full    <= 1'b0;   // release the gather for the next position
                    beat_in_pos <= 16'd0;
                end
                if (fifo_out_ready && fifo_out_valid) begin
                    gather_buf[beat_in_pos*ACT_W +: ACT_W] <= fifo_out_data;
                    if (beat_in_pos == (BEATS_PER_POS-1)) buf_full <= 1'b1;
                    else                                   beat_in_pos <= beat_in_pos + 16'd1;
                end
            end
        end
    end
    endgenerate
endmodule

`endif // NN2RTL_TOP_NO_STUBS
